.darma-loader-darma-custom-599 {
   width: 50px;
   height: 60px;
   color: var(--loader-color, #6d28d9);
   display: grid;
}
.darma-loader-darma-custom-599:before, .darma-loader-darma-custom-599:after  {
  content: "";
   background: linear-gradient(90deg,currentColor calc(100% - 15px),#0000 0) 0 50%/100% 10px, conic-gradient(from -136deg at 15px 50%,#0000 ,currentColor 1deg 90deg,#0000 91deg) 35px 0/100% 100%;
   background-repeat: repeat-x;
   animation: darma-loader-darma-custom-599-l6 1s infinite;
}
.darma-loader-darma-custom-599:after  {
  transform: scaleX(-1);
}
@keyframes darma-loader-darma-custom-599-l6  {
  80%,100%{background-position: 50px 50%,85px 0}
}

